              </v-img>
              <v-img :src="item.large" :lazy-src="item.small" contain class="mx-4 mt-16 d-md-none" height="400">
                <template v-slot:placeholder>
                  <v-row
                    class="fill-height ma-0"
                    align="center"
                    justify="center"
                  >
                    <v-progress-circular indeterminate color="grey lighten-5"></v-progress-circular>
                  </v-row>
                </template>
              </v-img>
            </v-col>
            <v-col md="3" lg="3" xl="3" class="d-flex align-center">
              <v-card 
                :color="item.background" 
                flat tile 
                class="mx-4 mt-n4"
                dark
              >
                <v-card-title v-text="item.title" class="text-h5"/>
                <v-card-text v-text="item.description" class="text-body-1 font-weight-light"/>
                <v-card-text class="mt-n6">
                  <div class="d-flex flex-row">
                    <v-icon small color="#eee">
                      mdi-clock-time-three-outline
                    </v-icon>
                    <v-card-text class="ml-n3 text-caption" v-text="item.time"/>
