                    </v-icon>
                    <v-card-text class="ml-n3 text-caption" v-text="item.location"/>
                  </div>
                </v-card-text>
                <v-card-actions class="ml-2">
                    <v-btn dark outlined rounded @click="item=details[(--id)%num]; restartChange()">上一张</v-btn>
                    <v-btn dark outlined rounded @click="item=details[(++id)%num]; restartChange()">下一张</v-btn>
                </v-card-actions>
              </v-card>
