<script>
import Blog from './components/Blog.vue';
import Info from './components/Info.vue';
import imageData from "./../contents/images/images.json"

export default {
  components: { 
    Blog, 
    Info 
    },

  data: () => ({ 
    value: 2, 
    details: [],
    item: {},
    id: 0,
    num: 0,
    change: undefined
  }),

  mounted(){
    this.details = imageData.images;
    this.details.sort(function() {
        return (0.5-Math.random());
    }); 
    for (var i in this.details) {
      this.details[i].large = require('./../contents/images/large/'+this.details[i].file);
      this.details[i].small = require('./../contents/images/small/'+this.details[i].file);
    }
    this.num = this.details.length;
    this.item = this.details[this.id];
    this.change = setInterval(()=>{
      this.item=this.details[(++this.id)%this.num];
    }, 12000);
  },
  
  methods:{
    restartChange() {
      clearInterval(this.change);
      this.change = setInterval(()=>{
        this.item=this.details[(++this.id)%this.num];
      }, 12000);
    }
  }
}
</script>
